-- big block-letter logo font: char -> main 8x8 tile. g/p/r/d have a tail in the cell
-- below (main+16); h/n also extend into the cell above (main-16). i/! are only 2px wide.
local LG={a=192,c=193,d=194,e=195,g=208,h=232,i=211,l=212,m=213,n=226,o=227,p=228,r=229,s=230,t=225,u=231,v=240,["8"]=241,["!"]=242}

-- draw TEXT centered horizontally with its top at y, 1px gap between letters.
-- lm/ls = letter main/shadow color; dm/ds = digit ("8") main/shadow. a darker copy
-- is drawn 1px lower behind the main copy to fake depth. wv (optional) = sine bob amplitude (px).
function draw_logo(txt,y,lm,ls,dm,ds,wv)
 local w=0
 for i=1,#txt do local c=sub(txt,i,i) w+=c==" " and 5 or (c=="i"or c=="!")and 3 or 9 end
 local x0=64-(w-1)\2
 for p=0,1 do
  local x=x0
  for i=1,#txt do
   local c=sub(txt,i,i)
   if c==" " then x+=5
   else
    local m,dig,nw=LG[c],c=="8",c=="i"or c=="!"
    pal(7,p<1 and(dig and ds or ls)or(dig and dm or lm))
    local gx,gy=x+(nw and -3 or 0),y+(p<1 and 1 or 0)+(wv and sin(time()*.5+i*.08)*wv or 0)
    spr(m,gx,gy)
    -- extensions are only 4px tall so two letters can share one tile (top half = a
    -- below-tail, bottom half = an above-riser): below draws the tile's top 4px, above its bottom 4px
    if c=="g"or c=="p"or c=="r"or c=="h"or c=="d"or c=="n" then sspr(m%16*8,m\16*8+8,8,4,gx,gy+8) end
    if c=="h"or c=="n" then sspr(m%16*8,m\16*8-4,8,4,gx,gy-4) end
    x+=nw and 3 or 9
   end
  end
 end
 pal()
end

-- print TXT with the logo's raised look: a darker copy 1px below, then the main colour on top.
-- shared by the menu and the high-score screens so embossed text reads the same everywhere.
function rprint(txt,x,y,m,s)
 print(txt,x,y+1,s)
 print(txt,x,y,m)
end

-- print s with any '$' drawn as the coin sprite (tile 67, 5px wide) -- the coin is the money symbol.
-- raised (1px shadow colour sh) when sh is set. for right/centre alignment, width = #s*4+2 (one coin).
function mprint(s,x,y,c,sh)
 for i=1,#s do local ch=sub(s,i,i)
  if ch=="$" then spr(67,x,y) x+=6
  else if sh then print(ch,x,y+1,sh) end x=print(ch,x,y,c) end
 end
end

-- flashing nav arrow built from the two arrow tiles: 18 (lit) + 19 (plain) alternate for the
-- flash. right=true points right; false flips to point left. inactive shows a dimmed plain frame.
function farrow(x,y,right,active)
 local f=not right
 if active then
  spr(time()%0.8<0.4 and 18 or 19,x,y,1,1,f)
 else
  pal(7,5) pal(6,13) pal(13,1) spr(19,x,y,1,1,f) pal()
 end
end